package bsr

// ByteSource identifies whether bytes are flowing from the user to target (client)
// or target to user (server)
type ByteSource uint8

// ByteDirections
const (
	UnknownByteSource ByteSource = iota
	Client
	Server
)

func (d ByteSource) String() string {
	switch d {
	case Client:
		return "client"

